example.code:
// Memoize expensive sort: items array changes trigger re-sort
const sortedItems = useMemo(
  () => items.slice().sort((a, b) => a.name.localeCompare(b.name)),
  [items],
);

// Memoize callbacks passed to memoized children to preserve referential equality
const handleItemClick = useCallback((id: string) => {
  setSelectedId(id);
}, []);
